import{_ as a,a as d,b as r,c as e}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as o,o as h,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const q=JSON.parse('{"title":"冗余备份与读取源切换","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Other/redundant-backup-and-read-source.md","filePath":"cn/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),i={name:"cn/Other/redundant-backup-and-read-source.md"};function p(s,t,b,c,u,_){return h(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="冗余备份与读取源切换" tabindex="-1">冗余备份与读取源切换 <a class="header-anchor" href="#冗余备份与读取源切换" aria-label="Permalink to &quot;冗余备份与读取源切换&quot;">​</a></h1><p>冗余备份用来给已经上传的文件再存一份副本。<br> 主文件和备份文件都可以作为读取源使用，平时看起来没有区别；区别只是文件实际从哪个存储渠道读取。</p><h2 id="冗余备份能做什么" tabindex="-1">冗余备份能做什么 <a class="header-anchor" href="#冗余备份能做什么" aria-label="Permalink to &quot;冗余备份能做什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>多存一份文件</td><td>把文件备份到另一个上传渠道，降低单个渠道出问题时的风险。</td></tr><tr><td>切换读取源</td><td>文件备份成功后，可以在主渠道和备份渠道之间切换读取。</td></tr><tr><td>单文件备份</td><td>在文件详情里给某一个文件备份。</td></tr><tr><td>批量备份</td><td>在管理页框选多个文件后批量备份。</td></tr><tr><td>全局冗余备份</td><td>在其他设置里按文件夹批量补备份。</td></tr></tbody></table><h2 id="冗余备份入口" tabindex="-1">冗余备份入口 <a class="header-anchor" href="#冗余备份入口" aria-label="Permalink to &quot;冗余备份入口&quot;">​</a></h2><p>冗余备份在：</p><p>系统配置 -&gt; 其他设置 -&gt; 冗余备份</p><p><img src="'+a+'" alt="冗余备份截图" loading="lazy"></p><p>这里适合给某个文件夹或全部文件统一补备份。<br> 备份渠道可以手动选择，也可以选择自动切换，让系统自己找合适的备份渠道。</p><h2 id="文件详情里备份" tabindex="-1">文件详情里备份 <a class="header-anchor" href="#文件详情里备份" aria-label="Permalink to &quot;文件详情里备份&quot;">​</a></h2><p>在管理后台点开文件详情，可以直接点击备份文件。</p><p><img src="'+d+'" alt="文件详情里文件备份" loading="lazy"></p><p>这个入口适合临时给单个重要文件补备份。<br> 备份成功后，文件详情里会出现可切换的读取源。</p><h2 id="框选批量备份" tabindex="-1">框选批量备份 <a class="header-anchor" href="#框选批量备份" aria-label="Permalink to &quot;框选批量备份&quot;">​</a></h2><p>在管理后台可以框选多个文件，然后执行批量备份。</p><p><img src="'+r+'" alt="批量备份截图" loading="lazy"></p><p>这个入口适合一次处理一批文件。<br> 框选备份、文件详情备份、其他设置里的冗余备份，本质上都是同一个备份功能，只是入口不同。</p><h2 id="备份成功后切换读取源" tabindex="-1">备份成功后切换读取源 <a class="header-anchor" href="#备份成功后切换读取源" aria-label="Permalink to &quot;备份成功后切换读取源&quot;">​</a></h2><p>备份完成后，文件详情里可以切换读取源：</p><table tabindex="0"><thead><tr><th>读取源</th><th>说明</th></tr></thead><tbody><tr><td>主渠道</td><td>从原始上传渠道读取文件。</td></tr><tr><td>备份渠道</td><td>从备份渠道读取文件。</td></tr></tbody></table><p><img src="'+e+'" alt="备份成功切换读取源" loading="lazy"></p><p>主渠道和备份渠道对用户访问来说没有区别。<br> 切到哪个读取源，后续访问文件时就优先从哪个渠道读取。</p><h2 id="哪些情况会跳过" tabindex="-1">哪些情况会跳过 <a class="header-anchor" href="#哪些情况会跳过" aria-label="Permalink to &quot;哪些情况会跳过&quot;">​</a></h2><p>备份时遇到下面情况会跳过，不是出错：</p><table tabindex="0"><thead><tr><th>情况</th><th>为什么跳过</th></tr></thead><tbody><tr><td>已经有备份</td><td>一个文件已经有备份时，不会重复备份。</td></tr><tr><td>主备渠道相同</td><td>备份渠道不能和主渠道一样，否则只是把文件放回原来的地方，没有备份意义。</td></tr><tr><td>没有可用备份渠道</td><td>当前没有合适的其他渠道可用。</td></tr></tbody></table><p>简单理解就是：备份必须放到另一个渠道里；已经备份过的文件不会重复占空间。</p><h2 id="主渠道和备份渠道怎么理解" tabindex="-1">主渠道和备份渠道怎么理解 <a class="header-anchor" href="#主渠道和备份渠道怎么理解" aria-label="Permalink to &quot;主渠道和备份渠道怎么理解&quot;">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>说明</th></tr></thead><tbody><tr><td>主渠道</td><td>文件第一次上传时使用的渠道。</td></tr><tr><td>备份渠道</td><td>后来通过冗余备份生成的副本渠道。</td></tr><tr><td>主读取源</td><td>当前从主渠道读取。</td></tr><tr><td>备份读取源</td><td>当前从备份渠道读取。</td></tr></tbody></table><p>主读取源和备份读取源没有功能高低之分。<br> 只要备份文件可用，切到备份读取源后，图片、视频、下载链接这些正常访问方式都照常使用。</p><h2 id="删除文件时会发生什么" tabindex="-1">删除文件时会发生什么 <a class="header-anchor" href="#删除文件时会发生什么" aria-label="Permalink to &quot;删除文件时会发生什么&quot;">​</a></h2><p>删除文件时，系统会同时删除主文件和备份文件。</p>',31)])])}const x=o(i,[["render",p]]);export{q as __pageData,x as default};
